const meta = $('Preparar Publicacao').first().json;
const data = $input.first().json;
const arr = Array.isArray(data) ? data : (data && Array.isArray(data.body) ? data.body : [data]);
const post = arr[0];
if (!post || !post.shortCode) {
  // para o fluxo aqui — antes o item-erro cascateava até o INSERT com nulls
  throw new Error('Apify nao retornou post valido: ' + meta.url);
}
// destino vem do form: trilha (default) | post_fixado | destaque
const tipo_artefato = meta.destino === 'post_fixado' ? 'post_fixado'
                    : meta.destino === 'destaque'    ? 'destaque'
                    : 'publicacao_avulsa';
return [{ json: {
  tipo_artefato,
  perfil: post.ownerUsername || '',
  trilha: meta.trilha,
  url: post.url,
  shortcode: post.shortCode,
  formato: post.type,
  caption: post.caption || '',
  display_url: post.displayUrl || '',
  video_url: post.videoUrl || '',
  likes: post.likesCount || 0,
  comments: post.commentsCount || 0,
  views: post.videoPlayCount || post.videoViewCount || 0,
  timestamp: post.timestamp,
  transcrever: post.type === 'Video' && Boolean(post.videoUrl),
  tipo_estrategico_manual: meta.tipo_estrategico_manual,
  etapa_funil_manual: meta.etapa_funil_manual,
  notas: meta.notas,
  origem: meta.origem,
  created_at: meta.created_at
}}];

const item = $('If Transcrever').first().json;
const trans = $json;
return [{ json: { ...item, transcricao: trans.text || '', language_code: trans.language_code || '', audio_duration_ms: trans.audio_duration || 0 } }];

// Classificação heurística (fallback) — a IA refina depois no Merge Guia.
// Processa TODOS os itens do input (multi-item no fluxo de perfil).
function matchAny(patterns, target) { return patterns.some(p => new RegExp(p, 'i').test(target)); }
function classify(i) {
  const caption = ((i.caption || '') + ' ' + (i.transcricao || '')).toLowerCase();
  const titulo = (i.titulo || '').toLowerCase();
  let tipo_estrategico = i.tipo_estrategico_manual;
  if (!tipo_estrategico) {
    if (i.tipo_artefato === 'destaque') {
      if (/quem sou|sobre mim|trajet|hist[oó]ria|apresent/.test(titulo)) tipo_estrategico = 'Quem Sou';
      else if (/result|transform|antes.*depois|case|sucesso|depoiment/.test(titulo)) tipo_estrategico = 'Resultados';
      else if (/m[eé]tod|protocolo|jornada|mentoria|clinic|tratament/.test(titulo)) tipo_estrategico = 'Metodologia/Produto';
      else if (/faq|d[uú]vid|pergunt|valor|investiment|pre[çc]/.test(titulo)) tipo_estrategico = 'FAQ';
      else if (/dica|educa|tutorial|passo|tip/.test(titulo)) tipo_estrategico = 'Dicas Grátis';
      else if (/oferta|comprar|vagas|inscri|link|bio|agend|whats/.test(titulo)) tipo_estrategico = 'Mentoria/Produto/Oferta';
      else if (/bastidor|vlog|rotina|home|pessoal|lifestyle/.test(titulo)) tipo_estrategico = 'Bastidores';
      else tipo_estrategico = 'Específico do Nicho';
    } else {
      const ap = matchAny(['quem sou','me chamo','me apresent','trabalho com','atendo','especialista em','sobre mim','minha hist'], caption);
      const pv = matchAny(['antes e depois','caso clínic','depoiment','transforma','resultado','paciente','aluno','aluna','mentorad','testemunh','evolu','jornada'], caption);
      const of = matchAny(['agend[ae]','agendar','avalia[cç][aã]o','link na bio','clique no link','whatsapp','comente.*receb','quero o','aula gratuita','ebook'], caption);
      if (i.posicao === 1 && ap) tipo_estrategico = 'Apresentação';
      else if (i.posicao === 3 && of) tipo_estrategico = 'Oferta/CTA';
      else if (of) tipo_estrategico = 'Oferta/CTA';
      else if (pv) tipo_estrategico = 'Prova Social';
      else if (ap) tipo_estrategico = 'Apresentação';
      else tipo_estrategico = 'Indefinido';
    }
  }
  let etapa_funil = i.etapa_funil_manual;
  if (!etapa_funil) {
    if (tipo_estrategico === 'Oferta/CTA' || tipo_estrategico === 'Mentoria/Produto/Oferta') etapa_funil = 'ACAO';
    else if (['Prova Social','Resultados','Quem Sou','Bastidores'].includes(tipo_estrategico)) etapa_funil = 'CONFIANCA';
    else etapa_funil = 'DESCOBERTA';
  }
  return { ...i, tipo_estrategico, etapa_funil };
}
return $input.all().map(n => ({ json: classify(n.json) }));

// Monta prompts pro guia de uso (metodologia DECIDA + Primeira Impressão).
const CATS_TRILHA = {
  clinic: {
    DESCOBERTA: ['Dica com oportunidade ou novidade','Dica prática ou informacional','Pauta quente ou popularidade','Posicionamento e contrassenso'],
    CONFIANCA: ['Bastidor e Elementos de autoridade','Dúvidas e quebras de objeção de consulta','Novo mecanismo e ou diferencial de produto','Prova comentada','Prova social dinâmica'],
    ACAO: ['Prova']
  },
  scale: {
    DESCOBERTA: ['Alerta de Erro','Dica e dúvidas','Histórias e curiosidades interessantes','Posicionamento com identificação de crença ou contrassenso','Tendências e pauta quente'],
    CONFIANCA: ['Inspiração','Marcos de autoridade','Prova','Remoção de objeções'],
    ACAO: ['Prova']
  }
};
const CATS_FIXADO = ['Apresentação','Prova Social','Oferta/CTA'];
const CATS_DESTAQUE = ['Quem Sou','Resultados','Metodologia/Produto','FAQ','Dicas Grátis','Mentoria/Produto/Oferta','Bastidores','Específico do Nicho'];

const SYS = `Você é o curador editorial do Banco de Referências da Case (mentoria de profissionais de saúde e mentores high-ticket). Sua função: analisar uma referência de conteúdo de Instagram e produzir o GUIA DE USO segundo a metodologia da Queila.

## Metodologia DECIDA (objetivo editorial em 3 grupos)
- DESCOBERTA (D+E — Descoberta + Entendimento): ser encontrada por quem ainda não conhece a expert. Critério: quem nunca viu entende em segundos por que é interessante. ~60% do calendário.
- CONFIANCA (C+I+D — Confiança + Identificação + Desejo): aprofundar vínculo com quem já viu. Critério: a pessoa pensa "essa é a especialista certa pra mim". ~30%.
- ACAO (A): chamar pra decisão — CTA direto, abertura de agenda/turma. Critério: próximo passo e janela de tempo imediatamente claros. ~10%.

## Posts fixados e destaques (Camada 1 — Primeira Impressão)
Posts fixados são a vitrine dos primeiros milissegundos: apresentação + método + prova social comentada (é obrigatório um dos três falar do método). Destaques são o menu do perfil: organizados por tema, com capas coerentes, incluindo prova social + método + bastidores. Ao analisar um fixado ou destaque, explique o papel dele NESSA vitrine — por que esse conteúdo merece o slot permanente e que percepção ele forma em quem bate o olho no perfil pela primeira vez.

## Os 3 campos que você escreve
- quando_usar: em que momento do calendário/estratégia da mentorada essa referência serve. Ex.: "Em fases de captação de público novo, quando a mentorada precisa quebrar a crença de que só ideias inéditas vendem e atrair quem ainda hesita em começar."
- por_que_funciona: o mecanismo persuasivo/narrativo REAL da peça. Ex.: "História de bilionários reais ancora autoridade por prova social concreta, e a reflexão final converte curiosidade em identificação com quem assiste."
- como_adaptar: instrução prática de transposição pro contexto da mentorada (clínica, consultório, mentoria). Ex.: "Trocar os irmãos Samwer por um caso da própria área que cresceu adaptando modelo existente, e manter a virada final ligando execução ao nicho dela."

## Regras de escrita
- Português brasileiro, 1-2 frases por campo, cada campo entre 80 e 280 caracteres.
- CONCRETO > abstrato: cite o elemento real da peça (o gancho, a história, o número, o formato), não conceito genérico. Proibido: "conteúdo de valor", "gera conexão", "engaja a audiência" sem dizer COMO.
- Baseie-se no que está NA transcrição/caption. Se o material é insuficiente (sem transcrição e caption curta), seja honesto e ancore no que dá pra ver (formato, título, métricas) sem inventar conteúdo.

## Output
APENAS um objeto JSON válido, sem markdown, sem cercas de código:
{"quando_usar":"...","por_que_funciona":"...","como_adaptar":"...","categoria":"...","etapa_funil":"DESCOBERTA|CONFIANCA|ACAO","objetivo":"Atrair|Identificar|Desejo|Confiar|Vender"}`;

function userPrompt(i) {
  let cats, papel;
  if (i.tipo_artefato === 'post_fixado') { cats = CATS_FIXADO; papel = 'POST FIXADO (vitrine do perfil — Camada 1)'; }
  else if (i.tipo_artefato === 'destaque') { cats = CATS_DESTAQUE; papel = 'DESTAQUE (menu do perfil — Camada 1)'; }
  else { cats = (CATS_TRILHA[i.trilha] ? Object.values(CATS_TRILHA[i.trilha]).flat() : []); papel = 'CONTEÚDO DE TRILHA (banco editorial por etapa DECIDA)'; }
  const parts = [
    `Tipo de referência: ${papel}`,
    `Trilha: ${i.trilha === 'clinic' ? 'Clínica (profissionais de saúde)' : 'Mentoria (mentores/experts)'}`,
    `Perfil: @${i.perfil || '?'}`,
    i.posicao ? `Posição fixado: ${i.posicao}` : '',
    i.titulo ? `Título do destaque: ${i.titulo}` : '',
    `Formato: ${i.formato || 'desconhecido'}`,
    (i.likes || i.views) ? `Métricas: ${i.likes || 0} likes · ${i.comments || 0} comentários · ${i.views || 0} views` : '',
    `Classificação heurística prévia: categoria=${i.tipo_estrategico || '?'} · etapa=${i.etapa_funil || '?'}`,
    `Categorias válidas (escolha EXATAMENTE uma): ${cats.join(' | ')}`,
    i.caption ? `\n--- CAPTION ---\n${String(i.caption).slice(0, 2000)}` : '',
    i.transcricao ? `\n--- TRANSCRIÇÃO ---\n${String(i.transcricao).slice(0, 8000)}` : '\n(sem transcrição disponível)'
  ];
  return parts.filter(Boolean).join('\n');
}

return $input.all().map(n => ({ json: { ...n.json, _sys_prompt: SYS, _user_prompt: userPrompt(n.json) } }));

// Junta resposta da IA com o item original. IA falhou => campos ficam null
// (ingest NUNCA bloqueia por causa do guia).
const prompts = $('Montar Prompt Guia').all();
const ETAPAS = ['DESCOBERTA','CONFIANCA','ACAO'];
const clean = s => (typeof s === 'string' && s.trim().length >= 20) ? s.trim().slice(0, 600) : null;
return $input.all().map((resp, idx) => {
  const item = { ...(prompts[idx] ? prompts[idx].json : {}) };
  delete item._sys_prompt; delete item._user_prompt;
  try {
    let content = resp.json.choices?.[0]?.message?.content || '';
    content = content.replace(/^```(json)?/m, '').replace(/```\s*$/m, '').trim();
    const start = content.indexOf('{'); const end = content.lastIndexOf('}');
    if (start >= 0 && end > start) content = content.slice(start, end + 1);
    const g = JSON.parse(content);
    item.quando_usar = clean(g.quando_usar);
    item.por_que_funciona = clean(g.por_que_funciona);
    item.como_adaptar = clean(g.como_adaptar);
    item.objetivo = (typeof g.objetivo === 'string' && g.objetivo.trim()) ? g.objetivo.trim().slice(0, 40) : null;
    if (!item.tipo_estrategico_manual && typeof g.categoria === 'string' && g.categoria.trim()) {
      item.tipo_estrategico = g.categoria.trim().slice(0, 80);
    }
    if (!item.etapa_funil_manual && ETAPAS.includes(g.etapa_funil)) {
      item.etapa_funil = g.etapa_funil;
    }
  } catch (e) {
    item._guia_error = String(e).slice(0, 200);
  }
  return { json: item };
});
